// Parse AI response
const aiResponse = JSON.parse($input.item.json.choices[0].message.content);
const previousState = $input.first().json.currentState || {};
const extractedParams = aiResponse.extracted_params || {};

// Update state with extracted parameters (merge with existing state)
const updatedState = {
  property_type: extractedParams.property_type || previousState.property_type || null,
  min_price: extractedParams.min_price !== null && extractedParams.min_price !== undefined ? extractedParams.min_price : (previousState.min_price || null),
  max_price: extractedParams.max_price !== null && extractedParams.max_price !== undefined ? extractedParams.max_price : (previousState.max_price || null),
  city: extractedParams.city || previousState.city || null,
  state: extractedParams.state || previousState.state || null,
  availability: true,
  bedrooms: extractedParams.bedrooms !== null && extractedParams.bedrooms !== undefined ? extractedParams.bedrooms : (previousState.bedrooms || null)
};

// Determine if we can execute a search
const canSearch = updatedState.property_type && updatedState.city;

// Create cache key
const cacheKey = updatedState.city ? `${updatedState.city}_${updatedState.property_type}` : null;

return {
  json: {
    intent: aiResponse.intent || 'clarification',
    updatedState: updatedState,
    responseMessage: aiResponse.response_message || 'How can I help you find a property?',
    canSearch: canSearch,
    cacheKey: cacheKey,
    hasCachedResults: false,
    cachedResults: null
  }
};

// Collect all property items from Supabase
const properties = $input.all().map(item => item.json);
const state = $('Process AI Response').item.json.updatedState || {};

// Filter by price if specified
let filteredProperties = properties;

if (state.min_price || state.max_price) {
  filteredProperties = properties.filter(prop => {
    const price = parseFloat(prop.price);
    const meetsMin = !state.min_price || price >= state.min_price;
    const meetsMax = !state.max_price || price <= state.max_price;
    return meetsMin && meetsMax;
  });
}

// Filter by bedrooms if specified
if (state.bedrooms !== null && state.bedrooms !== undefined) {
  filteredProperties = filteredProperties.filter(prop => prop.bedrooms === state.bedrooms);
}

// Get top 3 results
const top3 = filteredProperties.slice(0, 3);

// Format response
let message = '';

if (top3.length === 0) {
  message = `I couldn't find any ${state.property_type || 'properties'} in ${state.city || 'that location'} matching your criteria. Would you like to try a different city or adjust your budget?`;
} else {
  const propertyType = state.property_type || 'property';
  message = `Great news! I found ${top3.length} ${propertyType.toLowerCase()}(s) in ${state.city} that match your requirements:\n\n`;

  top3.forEach((prop, index) => {
    message += `${index + 1}. ${prop.property_type || 'Property'} - $${prop.price}/month\n`;
    message += `   📍 ${prop.city}, ${prop.state}\n`;
    if (prop.bedrooms) message += `   🛏️ ${prop.bedrooms} bedroom(s)\n`;
    if (prop.amenities && Array.isArray(prop.amenities) && prop.amenities.length > 0) {
      message += `   ✨ Amenities: ${prop.amenities.join(', ')}\n`;
    }
    message += `\n`;
  });

  message += `Would you like more details on any of these properties or search with different criteria?`;
}

return {
  json: {
    message: message,
    properties: top3,
    fromCache: false
  }
};

// Handle cases where we can't search yet (missing required fields)
const state = $input.item.json.updatedState || {};
const responseMessage = $input.item.json.responseMessage || '';

let message = '';

// Check what's missing and provide helpful guidance
if (!state.property_type && !state.city) {
  message = "I'd love to help you find the perfect property! To get started, please tell me:\n\n1. What type of property? (Apartment, Villa, Studio, Condo, or House)\n2. Which city? (New York, Miami, Los Angeles, San Francisco, Chicago, or Boston)";
} else if (!state.property_type) {
  message = `Great! I can help you search in ${state.city}. What type of property are you looking for?\n\n• Apartment\n• Villa\n• Studio\n• Condo\n• House`;

  if (state.bedrooms) {
    message += `\n\nI've noted you want ${state.bedrooms} bedroom(s).`;
  }
  if (state.min_price || state.max_price) {
    message += `\n\nBudget: `;
    if (state.min_price && state.max_price) {
      message += `$${state.min_price}-$${state.max_price}/month`;
    } else if (state.max_price) {
      message += `under $${state.max_price}/month`;
    } else if (state.min_price) {
      message += `at least $${state.min_price}/month`;
    }
  }
} else if (!state.city) {
  message = `Perfect! You're looking for a ${state.property_type}`;

  if (state.bedrooms) {
    message += ` with ${state.bedrooms} bedroom(s)`;
  }
  if (state.min_price || state.max_price) {
    if (state.min_price && state.max_price) {
      message += `, budget $${state.min_price}-$${state.max_price}/month`;
    } else if (state.max_price) {
      message += `, under $${state.max_price}/month`;
    } else if (state.min_price) {
      message += `, at least $${state.min_price}/month`;
    }
  }

  message += `.\n\nWhich city would you like to search in?\n\n• New York\n• Miami\n• Los Angeles\n• San Francisco\n• Chicago\n• Boston`;
} else {
  // Has both required fields - shouldn't be here, return AI message
  message = responseMessage || `I can search for ${state.property_type}s in ${state.city} for you.`;
}

return {
  json: {
    message: message,
    properties: [],
    fromCache: false
  }
};

const weather = $input.item.json || {};
const state = $('Process AI Response').item.json.updatedState || {};

const city = weather.name || state.city || 'that location';
const temp = weather.main?.temp ? Math.round(weather.main.temp) : 'N/A';
const feelsLike = weather.main?.feels_like ? Math.round(weather.main.feels_like) : 'N/A';
const description = weather.weather?.[0]?.description || 'unknown';
const humidity = weather.main?.humidity || 'N/A';

const message = `🌤️ Weather in ${city}:\n\n` +
  `Temperature: ${temp}°F (feels like ${feelsLike}°F)\n` +
  `Conditions: ${description}\n` +
  `Humidity: ${humidity}%\n\n` +
  `Is there anything else you'd like to know about properties in ${city}?`;

return {
  json: {
    message: message,
    weatherData: weather
  }
};

// Handle clarification intent - when AI determines user needs guidance
const message = $input.item.json.responseMessage || 'How can I help you find a property?';
const state = $input.item.json.updatedState || {};

let clarificationMessage = '';

// Provide specific guidance based on what's missing
if (!state.property_type && !state.city) {
  clarificationMessage = "I'd love to help you find the perfect property! To get started, please tell me:\n\n1. What type of property? (Apartment, Villa, Studio, Condo, or House)\n2. Which city? (New York, Miami, Los Angeles, San Francisco, Chicago, or Boston)\n\nFor example: 'Show me apartments in Miami' or 'I need a studio in New York'";
} else if (!state.property_type) {
  clarificationMessage = `Great! I can help you search in ${state.city}. What type of property are you looking for?\n\n• Apartment\n• Villa\n• Studio\n• Condo\n• House`;

  if (state.bedrooms) {
    clarificationMessage += `\n\nLooking for ${state.bedrooms} bedroom(s).`;
  }
  if (state.min_price || state.max_price) {
    clarificationMessage += `\n\nBudget: `;
    if (state.min_price && state.max_price) {
      clarificationMessage += `$${state.min_price}-$${state.max_price}/month`;
    } else if (state.max_price) {
      clarificationMessage += `under $${state.max_price}/month`;
    }
  }
} else if (!state.city) {
  clarificationMessage = `Perfect! You're looking for a ${state.property_type}`;

  if (state.bedrooms) {
    clarificationMessage += ` with ${state.bedrooms} bedroom(s)`;
  }
  if (state.min_price || state.max_price) {
    if (state.min_price && state.max_price) {
      clarificationMessage += `, budget $${state.min_price}-$${state.max_price}/month`;
    } else if (state.max_price) {
      clarificationMessage += `, under $${state.max_price}/month`;
    }
  }

  clarificationMessage += `.\n\nWhich city would you like to search in?\n\n• New York\n• Miami\n• Los Angeles\n• San Francisco\n• Chicago\n• Boston`;
} else {
  // Has both required fields - use AI's message
  clarificationMessage = message;
}

return {
  json: {
    message: clarificationMessage
  }
};

// Merge all possible response paths
const message = $input.item.json.message || 'No response available';

return {
  json: {
    success: true,
    message: message,
    timestamp: new Date().toISOString()
  }
};
